# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

class BankAccount(var balance: Int) extends Actor {
  def receive =
    {
      case AddAmount(amount) =>
        // YOUR CODE HERE
        this.balance += amount

      case SubAmount(amount) => 
        if (this.balance - amount >= 0)
          this.balance -= amount
        else println("not enough money")
    }
}

object BankAccount {
  def main(args: Array[String]) {
    val balance = new BankAccount(15)

    // deposit, withdrawal messages
    // note: you don't need to implement all of them for testing purposes
    balance ! AddAmount(20)
    println(balance.balance) // prints 35;
    balance ! SubAmount(8)  
    println(balance.balance)  // prints 27
  }
}

// message objects: deposit and withdrawal
case class AddAmount(amount: Int)
case class SubAmount(amount: Int)

val actor = BankAccount(0)

actor ! AddAmount(15)       // send to a mutable reference balance; 
actor.balance                // call the variable to print out its updated value;

// receive an actor system
import akka.actor._
implicit val sys = ActorSystem("bank")

object Main extends App {
  import actors.*

  val account = 
    context.spawn(
      classOf[BankAccount], 
      "1234"
    ) // a persistent ID for the account is always 1234;
  
  // deposit and withdraw messages for the account above:
  account ! AddAmount(8)
  account ! SubAmount(50)

  sys.stop(account)
}

class BankAccount(var balance: Int) extends Actor {
  def receive = {
    case AddAmount(amount) =>
      this.balance += amount

    case SubAmount(amount) => 
      if (this.balance - amount >= 0)
        this.balance -= amount
      else println("not enough money")
